                        dataList.add(new AuthPathData(data.getAppName(), data.getPath(), data.getEnabled()));
                        return dataList;
                    }, (List<AuthPathData> dataList1, List<AuthPathData> dataList2) -> {
                        dataList1.addAll(dataList2);
                        return dataList1;
                    }));
    }

