methodSignature: org.apache.shenyu.plugin.dubbo.common.AbstractDubboPlugin#doExecute
 methodBody: public Mono<Void> doExecute(final ServerWebExchange exchange,
                                   final ShenyuPluginChain chain,
                                   final SelectorData selector,
                                   final RuleData rule) {
String param=exchange.getAttribute(Constants.PARAM_TRANSFORM);
ShenyuContext shenyuContext=exchange.getAttribute(Constants.CONTEXT);
assert shenyuContext != null;
MetaData metaData=exchange.getAttribute(Constants.META_DATA);
if(!checkMetaData(metaData)){LOG.error(" path is : {}, meta data have error : {}",shenyuContext.getPath(),metaData);
exchange.getResponse().setStatusCode(HttpStatus.INTERNAL_SERVER_ERROR);
Object error=ShenyuResultWrap.error(exchange,ShenyuResultEnum.META_DATA_ERROR);
return WebFluxResultUtils.result(exchange,error);
}if(Objects.nonNull(metaData) && StringUtils.isNoneBlank(metaData.getParameterTypes()) && StringUtils.isBlank(param)){exchange.getResponse().setStatusCode(HttpStatus.INTERNAL_SERVER_ERROR);
Object error=ShenyuResultWrap.error(exchange,ShenyuResultEnum.DUBBO_HAVE_BODY_PARAM);
return WebFluxResultUtils.result(exchange,error);
}this.rpcContext(exchange);
return this.doDubboInvoker(exchange,chain,selector,rule,metaData,param);
}

