      return;
    }
switch (each.getGeneralContextType()) {
case Constants.ADD_GENERAL_CONTEXT_TYPE:      generalContextMapWithRpcType.put(each.getGeneralContextKey(),each.getGeneralContextValue());
    break;
case Constants.TRANSMIT_HEADER_TO_GENERAL_CONTEXT_TYPE:  final List<String> header=headers.get(each.getGeneralContextKey());
generalContextMapWithRpcType.put(StringUtils.isBlank(each.getGeneralContextValue()) ? each.getGeneralContextKey() : each.getGeneralContextValue(),CollectionUtils.isEmpty(header) ? null : String.join(", ",header));
break;
default:break;
}
}
);
generalContextMap.put(rpcType,generalContextMapWithRpcType);
}
);
exchange.getAttributes().put(Constants.GENERAL_CONTEXT,generalContextMap);
return chain.execute(exchange);
}

