 methodBody: protected Mono<Void> doExecute(final ServerWebExchange exchange, final ShenyuPluginChain chain,
                                   final SelectorData selector, final RuleData rule) {
if(Objects.isNull(rule)){return Mono.empty();
}final ShenyuContext shenyuContext=exchange.getAttribute(Constants.CONTEXT);
assert shenyuContext != null;
final SpringCloudSelectorHandle springCloudSelectorHandle=SpringCloudPluginDataHandler.SELECTOR_CACHED.get().obtainHandle(selector.getId());
