String serviceId=springCloudSelectorHandle.getServiceId();
if(StringUtils.isBlank(serviceId)){Object error=ShenyuResultWrap.error(exchange,ShenyuResultEnum.CANNOT_CONFIG_SPRINGCLOUD_SERVICEID);
